// Static brand assets served by the node: the favicon (the canonical Sphere
// mark, as SVG) and the raster icon + Open Graph banner (1200x630 PNG) used for
// social cards. The PNGs are embedded as base64 so the Worker stays dependency-
// free and needs no build-time asset pipeline; routes live in worker.ts.
//
// Regenerate the PNGs from assets/og-banner.png and assets/icon-256.png after
// editing them (they are the source of truth on disk).

/** Decode a base64 string to bytes for a binary Response body. */
export function bytesFromBase64(b64: string): Uint8Array {
  const bin = atob(b64);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
  return out;
}

